  const normalized =
    typeof rawValue === 'string' ? rawValue.trim().toLowerCase() : '';
  if (normalized && allowedReasoningEfforts.has(normalized)) {
    return normalized;
  }
  if (allowedReasoningEfforts.has(fallback)) {
    return fallback;
