function parseBooleanSetting(rawValue, fallback) {
  if (typeof rawValue === 'boolean') return rawValue;
  if (rawValue === 1 || rawValue === '1') return true;
  if (rawValue === 0 || rawValue === '0') return false;
  return Boolean(fallback);
}

